BEGIN TRANSACTION;

CREATE TABLE IF NOT EXISTS family_rail_packs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    family_group TEXT NOT NULL,
    pack_name TEXT NOT NULL,
    description TEXT,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS family_rail_pack_items (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    pack_id INTEGER NOT NULL,
    stage_no INTEGER NOT NULL,
    line_name TEXT NOT NULL,
    alias_name TEXT,
    line_type TEXT NOT NULL,
    power_domain TEXT,
    boot_phase TEXT,
    source_component TEXT,
    test_point TEXT,
    expected_voltage_min REAL,
    expected_voltage_typ REAL,
    expected_voltage_max REAL,
    expected_frequency TEXT,
    measurement_mode TEXT,
    is_critical INTEGER DEFAULT 0,
    priority_order INTEGER DEFAULT 0,
    description TEXT,
    FOREIGN KEY (pack_id) REFERENCES family_rail_packs(id) ON DELETE CASCADE
);

